package main

import (
	"bufio"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type Vector struct {
	data     []int
	size     int
	capacity int
}

func NewVector(capacity int) *Vector {
	return &Vector{
		data:     make([]int, capacity), // nunca use len(data) ou cap(data) ou qq método do go de manipulação de array
		size:     0,
		capacity: capacity,
	}
}

func (vec *Vector) String() string {
	return "[" + Join(vec.data[0:vec.size], ", ") + "]"
}

func (vec *Vector) Status() string {
	return fmt.Sprintf("size:%d capacity:%d", vec.size, vec.capacity)
}

func (vec *Vector) PushBack(value int) {

	if vec.size == vec.capacity {
		newCapacity := vec.capacity * 2

		if newCapacity == 0 {
			newCapacity = 1
		}

		newData := make([]int, newCapacity)
		for i := 0; i < vec.size; i++ {
			newData[i] = vec.data[i]
		}

		vec.data = newData
		vec.capacity = newCapacity
	}

	vec.data[vec.size] = value
	vec.size++
}

func (vec *Vector) Get(index int) int {
	return vec.data[index]
}

func (vec *Vector) At(index int) (int, error) {
	if index < 0 || index >= vec.size {
		return 0, errors.New("index out of range")
	}

	value := vec.Get(index)
	return value, nil
}

func (vec *Vector) Set(index int, value int) error {
	if index < 0 || index >= vec.size {
		return errors.New("index out of range")
	}

	vec.data[index] = value
	return nil

}

func (vec *Vector) Clear() {
	vec.size = 0
}

func (vec *Vector) Reserve(newCapacity int) {
	vec.capacity = newCapacity
}

func (vec *Vector) PopBack() error {
	if(vec.size == 0) {
		return errors.New("vector is empty")
	}
	vec.size--

	return nil
}

func (vec *Vector) Insert(index int, value int) error {
	if(index > vec.size) {
		return errors.New("index out of range")
	}

	if (vec.size == vec.capacity) {
		newCapacity := vec.capacity * 2
		if newCapacity == 0 {
			newCapacity = 1
		}

		newData := make([]int, newCapacity)
		for i := 0; i < vec.size; i++ {
			newData[i] = vec.data[i]
		}

		vec.data = newData
		vec.capacity = newCapacity
	}

	for i := vec.size; i > index; i-- {
		vec.data[i] = vec.data[i-1]
	}

	vec.data[index] = value
	vec.size++

	return nil
}

func (vec *Vector) Erase(index int) error{
	if index >= vec.size {
		return errors.New("index out of range")
	}

	for i := index; i < vec.size-1; i++{
		vec.data[i] = vec.data[i+1]
	}
	vec.size--

	return nil
}

func (vec *Vector) IndexOf(value int) int {
	for i := 0; i < vec.size; i++{
		if vec.data[i] == value {
			return i
		}
	}
	return -1
}

func (vec *Vector) Contains(value int) bool {
	return vec.IndexOf(value) != 1
}

func (vec *Vector) Capacity() int {
	return vec.capacity
}

func (vec *Vector) Slice(start int, end int) *Vector{
	if vec.size == 0 {
        return &Vector{data: vec.data, size: 0, capacity: 0}
    }

    start = (start%vec.size + vec.size) % vec.size
    end = (end%vec.size + vec.size) % vec.size

    var newSize int

    if start <= end {
        newSize = end - start
    } else {
        newSize = vec.size - start + end
    }

    if start < end {
        return &Vector{
            data:     vec.data[start:end],
            size:     newSize,
            capacity: len(vec.data[start:]),
        }
    }

    return &Vector{
        data:     vec.data[start:],
        size:     newSize,
        capacity: len(vec.data[start:]),
    }
}

func Join(slice []int, sep string) string {
	if len(slice) == 0 {
		return ""
	}
	var result strings.Builder
	fmt.Fprintf(&result, "%d", slice[0])
	for _, value := range slice[1:] {
		fmt.Fprintf(&result, "%s%d", sep, value)
	}
	return result.String()
}

func main() {
	var line, cmd string
	scanner := bufio.NewScanner(os.Stdin)

	v := NewVector(0)
	for {
		fmt.Print("$")
		if !scanner.Scan() {
			break
		}
		line = scanner.Text()
		fmt.Println(line)
		parts := strings.Fields(line)
		if len(parts) == 0 {
			continue
		}
		cmd = parts[0]

		switch cmd {
		case "end":
			return
		case "init":
			value, _ := strconv.Atoi(parts[1])
			v = NewVector(value)
		case "push":
			for _, part := range parts[1:] {
				value, _ := strconv.Atoi(part)
				v.PushBack(value)
			}
		case "show":
			fmt.Println(v)
		case "status":
			fmt.Println(v.Status())
		case "pop":
			err := v.PopBack()
			if err != nil {
				fmt.Println(err)
			}
		case "insert":
			 index, _ := strconv.Atoi(parts[1])
			 value, _ := strconv.Atoi(parts[2])
			 err := v.Insert(index, value)
			 if err != nil {
		 		fmt.Println(err)
			}
		case "erase":
			 index, _ := strconv.Atoi(parts[1])
			 err := v.Erase(index)
			 if err != nil {
			 	fmt.Println(err)
			 }
		case "indexOf":
			 value, _ := strconv.Atoi(parts[1])
			 index := v.IndexOf(value)
			 fmt.Println(index)
		case "contains":
			 value, _ := strconv.Atoi(parts[1])
			 if v.Contains(value) {
			 	fmt.Println("true")
			 } else {
			 	fmt.Println("false")
			 }
		case "clear":
			v.Clear()
		case "capacity":
			fmt.Println(v.Capacity())
		case "get":
			index, _ := strconv.Atoi(parts[1])
			value, err := v.At(index)
			if err != nil {
				fmt.Println(err)
			} else {
				fmt.Println(value)
			}
		case "set":
			 index, _ := strconv.Atoi(parts[1])
			 value, _ := strconv.Atoi(parts[2])
			 err := v.Set(index, value)
			 if err != nil {
			 	fmt.Println(err)
			 }
		case "reserve":
			newCapacity, _ := strconv.Atoi(parts[1])
			v.Reserve(newCapacity)
		case "slice":
			 start, _ := strconv.Atoi(parts[1])
			 end, _ := strconv.Atoi(parts[2])
			 slice := v.Slice(start, end)
			 fmt.Println(slice)
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
